def load_data(dbname):
    conn = sqlite3.connect('database/' + dbname+'.sqlite')  # Connect to SQL database (SQLlite)
    
    cursor = conn.cursor()  
      
    query="SELECT * from documents;"     
          
    data_rows  = cursor.execute(query)       
        
    for row in list(data_rows):             
          print("Data Row: ",row )  # Print each user's information and email id    
  
